#include <stdio.h>

void initialize_2d_array(int rows, int columns, int array[rows][columns]) {
 for (int i = 0; i < rows; i++) {
 for (int j = 0; j < columns; j++) {
 array[i][j] = 0;
 }
 }
}

// Example usage:
int main() {
 int array[3][4];
 initialize_2d_array(3, 4, array);
 return 0;
}
